+        Self {
+            base: BaseConnector::new(ConnectorId::from_static("test:minimal:v1")),
+        }
+    }
+}
+
+#[derive(Debug)]
+struct RateLimitedConnector {
+    base: BaseConnector,
+    declarations: RateLimitDeclarations,
+}
